refsection.programlisting:
// Compare one image with itself, a brightness-shifted copy, and a different scene.
base = imread(fullpath(getIPCVpath() + "/images/opencv_smarties.png"));
base = imresize(base, [240 320]);
brighter = im2uint8(min(im2double(base) * 1.35, 1));
different = imread(fullpath(getIPCVpath() + "/images/opencv_fruits.jpg"));
different = imresize(different, [240 320]);

[hBase, cells] = imcalchist(base, 32);
[hSame, cells] = imcalchist(base, 32);
[hBright, cells] = imcalchist(brighter, 32);
[hDifferent, cells] = imcalchist(different, 32);

hBase = hBase / sum(hBase);
hSame = hSame / sum(hSame);
hBright = hBright / sum(hBright);
hDifferent = hDifferent / sum(hDifferent);

// Correlation: larger is more similar. Bhattacharyya: smaller is more similar.
sameCorrelation = imcomparehist(hBase, hSame, "correlation");
brightCorrelation = imcomparehist(hBase, hBright, "correlation");
differentCorrelation = imcomparehist(hBase, hDifferent, "correlation");
sameDistance = imcomparehist(hBase, hSame, "bhattacharyya");
brightDistance = imcomparehist(hBase, hBright, "bhattacharyya");
differentDistance = imcomparehist(hBase, hDifferent, "bhattacharyya");

mprintf("Comparison       Correlation    Bhattacharyya\n");
mprintf("same image       %8.4f       %8.4f\n", sameCorrelation, sameDistance);
mprintf("brighter copy    %8.4f       %8.4f\n", brightCorrelation, brightDistance);
mprintf("different image  %8.4f       %8.4f\n", differentCorrelation, differentDistance);

subplot(2, 2, 1);
imshow(base);
title("Base");
subplot(2, 2, 2);
imshow(brighter);
title("Brighter copy");
subplot(2, 2, 3);
imshow(different);
title("Different image");
subplot(2, 2, 4);
plot(cells, hBase(:, 1), "r");
plot(cells, hBright(:, 1), "m");
plot(cells, hDifferent(:, 1), "b");
title("Red-channel normalized histograms");
